    : 'Respond in the user\'s language when possible; default to natural, engaging English.';
  const contextText = snippets
    .map(
      (snippet, index) =>
        `# Source ${index + 1}: ${snippet.file} — ${snippet.heading}\n${snippet.text}`
    )
    .join('\n\n');
