    provider: row.provider || '',
    metadata: (() => {
      try {
        const decoded = decryptText(row.metadata || '');
        return decoded ? JSON.parse(decoded) : {};
      } catch {
        return {};
      }
    })(),
    createdAt: row.created_at || null
  }));
