          </mesh>
          <Environment preset="city" />
        </Canvas>
      </div>
      <div className="relative z-10 p-5 h-full w-full">
        {children}
      </div>
    </div>
  );
}

HoloCard.propTypes = {
  children: PropTypes.node.isRequired,
  distort: PropTypes.number,
  className: PropTypes.string
};

