                                <NextGenNode {...nodeData.vault} activeKey={activeNode} onHover={setActiveNode} />
                            </>
                        )}

                        <NextGenNode {...nodeData.core} activeKey={activeNode} onHover={setActiveNode} />
                    </AnimatePresence>

                </div>
            </div>
        </div>
    );
}

