            </div>
          </div>
        </div>
      ) : null}

      {stepId === 'solana' ? (
        <div className="stack" style={{ gap: 10 }}>
          <div className="muted">
            Active Solana identity: {hasSolana ? session.solanaWalletAddress : 'Not connected'}
          </div>
          <label className="form-field">
            Privacy vault recipient
            <input
              className="form-input"
              value={solanaVault}
