    const outPath = path.resolve(settings.reportMd);
    fs.mkdirSync(path.dirname(outPath), { recursive: true });
    fs.writeFileSync(outPath, markdown);
  }

  if (settings.enforce && failures.length) {
    process.exit(2);
  }
}

